data.content:
For boundary testing in MSTest 3.x, the key assertions you want are:

| Scenario | Assertion |
|---|---|
| Grade cutoff values | `Assert.AreEqual(expected, actual)` with `[DataRow]` |
| Score within valid range | `Assert.IsInRange(actual, low, high)` |
| Score above/below threshold | `Assert.IsGreaterThan` / `Assert.IsLessThan` |
| Invalid input throws | `Assert.ThrowsExactly<T>(() => ...)` |

Here's a complete test class for your `ScoreCalculator`:

```csharp
using Contoso.Scoring;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator;

    public ScoreCalculatorTests()
    {
        _calculator = new ScoreCalculator();
    }

    // --- CalculatePercentage: boundary & validation ---

    [TestMethod]
    [DataRow(0, 10, 0.0, DisplayName = "Zero correct")]
    [DataRow(10, 10, 100.0, DisplayName = "All correct")]
    [DataRow(1, 1, 100.0, DisplayName = "Min total")]
    [DataRow(5, 10, 50.0, DisplayName = "Half correct")]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(
        int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);

        Assert.AreEqual(expected, result);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade: boundary values at each cutoff ---

    [TestMethod]
    [DataRow(100.0, "A")]
    [DataRow(90.0, "A", DisplayName = "A lower bound")]
    [DataRow(89.99, "B", DisplayName = "Just below A")]
    [DataRow(80.0, "B", DisplayName = "B lower bound")]
    [DataRow(79.99, "C", DisplayName = "Just below B")]
    [DataRow(70.0, "C", DisplayName = "C lower bound")]
    [DataRow(69.99, "D", DisplayName = "Just below C")]
    [DataRow(60.0, "D", DisplayName = "D lower bound")]
    [DataRow(59.99, "F", DisplayName = "Just below D")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(
        double percentage, string expectedGrade)
    {
        var grade = _calculator.GetGrade(percentage);

        Assert.AreEqual(expectedGrade, grade);
    }

    // --- NormalizeScore: clamping & range ---

    [TestMethod]
    [DataRow(50.0, 100.0, 50.0)]
    [DataRow(0.0, 100.0, 0.0, DisplayName = "Zero raw score")]
    [DataRow(100.0, 100.0, 100.0, DisplayName = "Max raw score")]
    public void NormalizeScore_ValidInputs_ReturnsExpected(
        double rawScore, double maxRaw, double expected)
    {
        var result = _calculator.NormalizeScore(rawScore, maxRaw);

        Assert.AreEqual(expected, result);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        var result = _calculator.NormalizeScore(150.0, 100.0);

        Assert.AreEqual(100.0, result);
        Assert.IsLessThanOrEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRawScore_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMaxRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));
    }
}
```

**Key patterns used:**

- **`Assert.IsInRange(actual, low, high)`** — verifies results stay within valid bounds (0–100)
- **`Assert.IsLessThanOrEqual`** — confirms clamping behavior
- **`Assert.ThrowsExactly<T>`** — tests each validation guard precisely
- **`[DataRow]` at boundaries** — tests both sides of each grade cutoff (e.g., `90.0` → A, `89.99` → B)
- **Sealed class + constructor init** — follows MSTest 3.x best practices
